def transform(xs):
    # Calculate the median of the input list
    sorted_xs = sorted(xs)
    n = len(sorted_xs)
    if n % 2 == 1:
        median = sorted_xs[n // 2]
    else:
        median = (sorted_xs[n // 2 - 1] + sorted_xs[n // 2]) / 2

    # Create a new list with elements transformed based on their relation to the median
    result = []
    for x in xs:
        if x > median:
            result.append(x - median)
        elif x < median:
            result.append(x - median)
        else:
            result.append(0)

    # Sort the result in descending order
    result.sort(reverse=True)

    return result
